@Test
public void handlesShortPseudoXmlDecl() {
    String html = "<script> var a='<'; var b='>'; </script>";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertEquals("<script> var a='&lt;'; var b='&gt;'; </script>", doc.html());
}

@Test
public void handlesEmptyPseudoXmlDecl() {
    String html = "<script> var a='<??>'; </script>";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertEquals("<script> var a='\n <!--?-->'; </script>", doc.html());
}

@Test
public void handlesExclamationPseudoXmlDecl() {
    String html = "<script> var a='<!test>'; </script>";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertTrue(doc.html().contains("<script>"));
}
